var skillName = "active.launch_construct_shoulder_rocket";
var skillOpt = Templates.All<SkillTemplate>().FirstOrDefault(s => s.name == skillName);
Assert.NotNull(skillOpt, $"Skill/Perk '{skillName}' should exist");
skillOpt

var handlers = skillOpt.EventHandlers;
Assert.NotNull(handlers, "EventHandlers should not be null");
Assert.True(handlers.Count > 0, "Should have at least one EventHandler");
var handler = handlers.FirstOrDefault(h => h._type == "SetUsesPerElement");
Assert.NotNull(handler, $"Should find SetUsesPerElement EventHandler");
handler

var fieldValue = handler.UsesPerElement;
Assert.NotNull(fieldValue, "UsesPerElement should be populated");
fieldValue
